// src/lib/images.ts
//
// Central image-slot registry. The WebP files live in /public/images/
// and are generated by scripts/download-and-process-images.mjs. Each slot
// knows its own widths, so React components can just ask for `getImage(slot)`
// and drop the result onto a native <img> tag.
//
// All slot names match the files on disk. Do not hand-edit.

export type HeroSlot =
  | 'hero-aurora'
  | 'hero-dusk-lake';

export type TripSlot =
  | 'trip-aurora-chase'
  | 'trip-cabin-life'
  | 'trip-food'
  | 'trip-forest-walk'
  | 'trip-night-forest'
  | 'trip-silence'
  | 'trip-solo-trek';

export type PillarSlot =
  | 'pillar-cold'
  | 'pillar-shelter'
  | 'pillar-people';

export type CategorySlot =
  | 'category-aurora'
  | 'category-cabins'
  | 'category-food'
  | 'category-seasons';

export type AsideSlot = 'aside-vesa';

export type ImageSlot =
  | HeroSlot
  | TripSlot
  | PillarSlot
  | CategorySlot
  | AsideSlot;

type ImageMeta = {
  sizes: number[];    // widths available on disk, largest first
  ratio: '21:9' | '3:2';
  alt: string;        // default alt — components may override
};

// Keep order consistent with scripts/download-and-process-images.mjs
