export type ResolvedImage = {
  /** URL of the largest available size — use this as <img src>. */
  src: string;
  /** Full `srcset` string with every available size. */
  srcSet: string;
  /** Matching `sizes` attribute hint. */
  sizes: string;
  /** Alt text for accessibility. */
  alt: string;
  /** Aspect ratio helper for CSS (e.g. "3 / 2"). */
  aspectRatio: string;
};

/**
 * Resolve an image slot into attributes you can drop straight onto `<img>`.
 * @param slot     slot name registered above
 * @param sizesHint optional custom `sizes` string (defaults to full-width)
 * @param altOverride optional alt to use instead of the registry default
 */
export function getImage(
  slot: ImageSlot,
  sizesHint?: string,
  altOverride?: string
): ResolvedImage {
  const meta = REGISTRY[slot];
  const sorted = [...meta.sizes].sort((a, b) => b - a); // largest first
  const largest = sorted[0];

  const srcSet = sorted
    .map((w) => `/images/${slot}-${w}.webp ${w}w`)
    .join(', ');

  const defaultSizes =
    meta.ratio === '21:9'
      ? '(max-width: 768px) 100vw, (max-width: 1200px) 100vw, 1600px'
      : '(max-width: 640px) 100vw, (max-width: 1024px) 50vw, 33vw';

  return {
    src: `/images/${slot}-${largest}.webp`,
    srcSet,
    sizes: sizesHint ?? defaultSizes,
    alt: altOverride ?? meta.alt,
    aspectRatio: meta.ratio === '21:9' ? '21 / 9' : '3 / 2',
  };
}

/** For `<link rel="preload">` in <head> — returns just the largest URL. */
export function getImagePreloadSrc(slot: ImageSlot): string {
  const meta = REGISTRY[slot];
  const largest = [...meta.sizes].sort((a, b) => b - a)[0];
  return `/images/${slot}-${largest}.webp`;
}
